    items: { value: string }[],
    explicit?: string | string[],
) {
    if (explicit !== undefined) {
        return explicit;
    }
    if (type === 'multiple') {
        return [items[0]?.value].filter(Boolean) as string[];
    }
    return items[0]?.value ?? '';
