    }

    return context;
}

function clampIndex(index: number, count: number, loop: boolean) {
    if (count <= 0) {
        return 0;
    }

    if (loop) {
        return (index + count) % count;
    }

    return Math.min(Math.max(index, 0), count - 1);
}

type CarouselProps = ViewProps & {
    defaultIndex?: number;
    index?: number;
    loop?: boolean;
    onIndexChange?: (index: number) => void;
};

function Carousel({
    children,
    defaultIndex = 0,
    index,
    loop = false,
    onIndexChange,
    style,
    ...props
}: CarouselProps) {
    const scrollRef = React.useRef<ScrollView>(null);
    const [internalIndex, setInternalIndex] = React.useState(defaultIndex);
    const [count, setCount] = React.useState(0);
    const [viewportWidth, setViewportWidth] = React.useState(0);
    const isControlled = index !== undefined;
    const resolvedIndex = clampIndex(isControlled ? index : internalIndex, count, loop);

    const setIndex = React.useCallback(
        (nextIndex: number) => {
            const clamped = clampIndex(nextIndex, count, loop);

            if (!isControlled) {
                setInternalIndex(clamped);
            }

            onIndexChange?.(clamped);
        },
        [count, isControlled, loop, onIndexChange],
    );

    const scrollToIndex = React.useCallback(
        (nextIndex: number) => {
            const clamped = clampIndex(nextIndex, count, loop);

            if (viewportWidth > 0) {
                scrollRef.current?.scrollTo({
                    x: clamped * viewportWidth,
                    animated: true,
                });
            }

            setIndex(clamped);
        },
        [count, loop, setIndex, viewportWidth],
    );

    React.useEffect(() => {
        if (viewportWidth > 0) {
            scrollRef.current?.scrollTo({
                x: resolvedIndex * viewportWidth,
                animated: false,
            });
        }
    }, [resolvedIndex, viewportWidth]);

    return (
        <CarouselContext.Provider
            value={{
                count,
                setCount,
                index: resolvedIndex,
                viewportWidth,
                setViewportWidth,
                scrollToIndex,
                loop,
                scrollRef,
            }}
        >
            <View style={[styles.root, style]} {...props}>
                {children}
            </View>
        </CarouselContext.Provider>
    );
}

