type ItemVariant = 'default' | 'destructive';

type DropdownMenuItemProps = PressableProps & {
    children?: React.ReactNode;
    /** Adds leading inset for icon rows (shadcn `inset`). */
    inset?: boolean;
    variant?: ItemVariant;
    /** When false, the menu stays open after press (default: true). */
    closeOnPress?: boolean;
};

function DropdownMenuItem({
    children,
    onPress,
    style,
    disabled,
    inset,
    variant = 'default',
    closeOnPress = true,
    ...props
}: DropdownMenuItemProps) {
    const theme = useRegistryTheme();
    const { setOpen } = useDropdownMenuContext();
    const destructive = variant === 'destructive';

    return (
        <Pressable
            disabled={disabled}
            onPress={(event) => {
                if (disabled) {
                    return;
                }
                onPress?.(event);
                if (closeOnPress) {
                    setOpen(false);
                }
            }}
            style={({ pressed }) => [
                styles.item,
                inset && styles.itemInset,
                {
                    backgroundColor: pressed
                        ? destructive
                            ? 'rgba(239, 68, 68, 0.12)'
                            : theme.secondary
                        : theme.background,
                    borderColor: 'transparent',
                    opacity: disabled ? 0.45 : 1,
                },
                style as object,
            ]}
            {...props}
        >
            <TextStyleContext.Provider
                value={{
                    color: destructive ? '#dc2626' : theme.foreground,
                    fontSize: 15,
                    fontWeight: '400',
                    lineHeight: 20,
                    flex: 1,
                }}
            >
                <View style={styles.itemInner}>
                    {typeof children === 'string' ? <UiText>{children}</UiText> : children}
                </View>
            </TextStyleContext.Provider>
        </Pressable>
    );
}

type DropdownMenuCheckboxItemProps = PressableProps & {
    checked?: boolean;
