        shadowOpacity: 0.1,
        shadowRadius: 24,
        elevation: 8,
    },
    header: {
        gap: 6,
    },
});

export {
    HoverCard,
    HoverCardContent,
    HoverCardDescription,
    HoverCardHeader,
    HoverCardTitle,
    HoverCardTrigger,
