                    hitSlop={10}
                    onPress={() => onClear?.()}
                    style={styles.clearHit}
                >
                    <Text variant="muted" style={styles.clearGlyph}>
                        ×
                    </Text>
                </Pressable>
            ) : rightSlot ? (
                <View style={styles.slot}>{rightSlot}</View>
            ) : null}
        </View>
    );
}

